import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (name, tfm, pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((k, bv, av))
    else:
        unchanged.append((k, bv))

print('=== CHANGES ===')
if changes:
    for (proj, tfm, pkg), bv, av in changes:
        print(f'{proj} ({tfm}) | {pkg} | {bv} -> {av}')
else:
    print('None')

print()
print('=== UNCHANGED ===')
for (proj, tfm, pkg), v in unchanged:
    print(f'{proj} ({tfm}) | {pkg} | {v}')
"

